import React, { Component } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  Modal,
  StyleSheet,
  Platform,
} from 'react-native';

function formatDuration(ms) {
  var secs = Math.round(ms / 1000);
  var m = Math.floor(secs / 60);
  var s = secs % 60;
  return m + ':' + (s < 10 ? '0' : '') + s;
}

export default class AudioPlayer extends Component {
  constructor(props) {
    super(props);
    this.state = {
      playing: false,
      currentTime: 0,
      duration: 0,
      error: false,
    };
    this._audio = null;
  }

  componentDidUpdate(prevProps) {
    if (this.props.visible && !prevProps.visible) {
      this.setState({ playing: false, currentTime: 0, error: false });
    }
    if (!this.props.visible && prevProps.visible) {
      this.stopAudio();
    }
  }

  componentWillUnmount() {
    this.stopAudio();
  }

  playAudio() {
    var { source } = this.props;
    var self = this;

    if (Platform.OS !== 'web') return;

    try {
      if (this._audio) {
        this._audio.pause();
        this._audio = null;
      }

      this._audio = new Audio(source);
      this._audio.addEventListener('loadedmetadata', function () {
        self.setState({ duration: self._audio.duration * 1000 });
      });
      this._audio.addEventListener('timeupdate', function () {
        self.setState({ currentTime: self._audio.currentTime * 1000 });
      });
      this._audio.addEventListener('ended', function () {
        self.setState({ playing: false, currentTime: 0 });
      });
      this._audio.addEventListener('error', function () {
        self.setState({ playing: false, error: true });
      });
      this._audio.play();
      this.setState({ playing: true, error: false });
    } catch (e) {
      this.setState({ error: true });
    }
  }

  pauseAudio() {
    if (this._audio) {
      this._audio.pause();
      this.setState({ playing: false });
    }
  }

  stopAudio() {
    if (this._audio) {
      this._audio.pause();
      this._audio.src = '';
      this._audio = null;
    }
    this.setState({ playing: false, currentTime: 0 });
  }

  render() {
    var { visible, fileName, duration: propDuration, onClose } = this.props;
    var { playing, currentTime, duration, error } = this.state;
    var self = this;
    var totalMs = duration || propDuration || 0;
    var progress = totalMs > 0 ? (currentTime / totalMs) : 0;

    return (
      <Modal
        visible={visible}
        transparent={true}
        animationType="fade"
        onRequestClose={onClose}
      >
        <TouchableOpacity style={styles.overlay} activeOpacity={1} onPress={onClose}>
          <View style={styles.card}>
            <TouchableOpacity activeOpacity={1} onPress={function (e) { e.stopPropagation && e.stopPropagation(); }}>
              <View style={styles.header}>
                <Text style={styles.title} numberOfLines={1}>{fileName || 'Audio'}</Text>
                <TouchableOpacity style={styles.closeBtn} onPress={onClose}>
                  <Text style={styles.closeText}>X</Text>
                </TouchableOpacity>
              </View>

              {error ? (
                <View style={styles.errorBox}>
                  <Text style={styles.errorText}>Failed to play audio</Text>
                </View>
              ) : (
                <View style={styles.playerArea}>
                  <TouchableOpacity
                    style={styles.playBtn}
                    onPress={function () {
                      if (playing) { self.pauseAudio(); }
                      else { self.playAudio(); }
                    }}
                  >
                    <Text style={styles.playIcon}>{playing ? '||' : '>'}</Text>
                  </TouchableOpacity>

                  <View style={styles.progressArea}>
                    <View style={styles.progressTrack}>
                      <View style={[styles.progressFill, { width: (progress * 100) + '%' }]} />
                    </View>
                    <View style={styles.timeRow}>
                      <Text style={styles.timeText}>{formatDuration(currentTime)}</Text>
                      <Text style={styles.timeText}>{formatDuration(totalMs)}</Text>
                    </View>
                  </View>
                </View>
              )}
            </TouchableOpacity>
          </View>
        </TouchableOpacity>
      </Modal>
    );
  }
}

var styles = StyleSheet.create({
  overlay: {
    flex: 1,
    backgroundColor: 'rgba(0,0,0,0.7)',
    justifyContent: 'center',
    alignItems: 'center',
    padding: 24,
  },
  card: {
    backgroundColor: '#222529',
    borderRadius: 12,
    width: '100%',
    maxWidth: 400,
    overflow: 'hidden',
  },
  header: {
    flexDirection: 'row',
    alignItems: 'center',
    paddingHorizontal: 16,
    paddingVertical: 12,
    borderBottomWidth: 1,
    borderBottomColor: '#383838',
  },
  title: {
    flex: 1,
    color: '#FFFFFF',
    fontSize: 15,
    fontWeight: '600',
  },
  closeBtn: {
    width: 32,
    height: 32,
    borderRadius: 4,
    backgroundColor: '#383838',
    justifyContent: 'center',
    alignItems: 'center',
    marginLeft: 12,
  },
  closeText: {
    color: '#D1D2D3',
    fontSize: 14,
    fontWeight: 'bold',
  },
  playerArea: {
    flexDirection: 'row',
    alignItems: 'center',
    padding: 20,
  },
  playBtn: {
    width: 48,
    height: 48,
    borderRadius: 24,
    backgroundColor: '#007A5A',
    justifyContent: 'center',
    alignItems: 'center',
    marginRight: 16,
  },
  playIcon: {
    color: '#FFFFFF',
    fontSize: 18,
    fontWeight: 'bold',
  },
  progressArea: {
    flex: 1,
  },
  progressTrack: {
    height: 4,
    backgroundColor: '#383838',
    borderRadius: 2,
    overflow: 'hidden',
  },
  progressFill: {
    height: 4,
    backgroundColor: '#1264A3',
    borderRadius: 2,
  },
  timeRow: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    marginTop: 6,
  },
  timeText: {
    color: '#ABABAD',
    fontSize: 12,
  },
  errorBox: {
    padding: 20,
    alignItems: 'center',
  },
  errorText: {
    color: '#E01E5A',
    fontSize: 14,
  },
});
